  1→// backend/src/services/query-engine.ts
  2→// Query engine — handles q:* protocol frames for typed reactive queries.
  3→// Module singleton: subscription state + dispatch logic.
  4→// Works for both local WS and relay-tunneled connections via WsSendable.
  5→//
  6→// Subscription model: ID-keyed. Client assigns IDs ("sub_1", "sub_2") and
  7→// server echoes them back on q:snapshot/q:delta so the client can route
  8→// to the correct callback.
  9→
 10→import { match } from "ts-pattern";
 11→import { getDatabase } from "../lib/database";
 12→import {
 13→  getDashboardWorkspaces,
 14→  getStats,
 15→  getSessionsByWorkspaceId,
 16→  getSessionById,
 17→  getMessages,
 18→  hasOlderMessages,
 19→  hasNewerMessages,
 20→  getWorkspaceRaw,
 21→  getMaxMessageSeq,
 22→  getMessagesDelta,
 23→  resetStatsCache,
 24→  getWorkspacesByRepo,
 25→  getWorkspacesBySessionIds,
 26→  getAllRepositorySummaries,
 27→  getSessionRaw,
 28→} from "../db";
 29→import { computeWorkspacePath } from "../middleware/workspace-loader";
 30→import { writeUserMessage } from "./message-writer";
 31→import { getConnection } from "./ws.service";
 32→import { resolve as resolveToolRelay, reject as rejectToolRelay } from "./tool-relay";
 33→import {
 34→  QUERY_RESOURCES,
 35→  MUTATION_NAMES,
 36→  COMMAND_NAMES,
 37→  type MutationName,
 38→  type CommandName,
 39→  type QueryResource,
 40→  type QServerFrame,
 41→} from "../../../shared/types/query-protocol";
 42→
 43→// ---- Subscription State ----
 44→
 45→type QueryParams = Record<string, unknown>;
 46→
 47→interface ResourceFrameInput {
 48→  id: string;
 49→  resource: string;
 50→  params: QueryParams;
 51→}
 52→
 53→interface UnsubscribeFrameInput {
 54→  id: string;
 55→}
 56→
 57→interface MutateFrameInput {
 58→  id: string;
 59→  action: string;
 60→  params: QueryParams;
 61→}
 62→
 63→interface CommandFrameInput {
 64→  id: string;
 65→  command: string;
 66→  params: QueryParams;
 67→}
 68→
 69→interface Sub {
 70→  id: string;
 71→  resource: QueryResource;
 72→  params: QueryParams;
 73→}
 74→
 75→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 76→const subs = new Map<string, Map<string, Sub>>();
 77→
 78→/** For messages: track last seen seq per subscription for delta push.
 79→ *  Key: `${connectionId}:${subId}` → lastSeq */
 80→const messageCursors = new Map<string, number>();
 81→
 82→// ---- Public API ----
 83→
 84→/**
 85→ * Handle an incoming q:* frame from an authenticated connection.
 86→ * Registered as onQueryFrame in ws.service protocol handlers.
 87→ */
 88→export function handleFrame(connectionId: string, msg: QueryParams): void {
 89→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 90→
 91→  try {
 92→    match(type)
 93→      .with("q:request", () => {
 94→        handleRequest(connectionId, parseResourceFrame(msg));
 95→      })
 96→      .with("q:subscribe", () => {
 97→        handleSubscribe(connectionId, parseResourceFrame(msg));
 98→      })
 99→      .with("q:unsubscribe", () => {
100→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
101→      })
102→      .with("q:mutate", () => {
103→        handleMutate(connectionId, parseMutateFrame(msg));
104→      })
105→      .with("q:command", () => {
106→        handleCommand(connectionId, parseCommandFrame(msg));
107→      })
108→      .with("q:tool_response", () => {
109→        handleToolResponse(msg);
110→      })
111→      .otherwise(() => {
112→        sendFrame(connectionId, {
113→          type: "q:error",
114→          id: getFrameId(msg),
115→          code: "UNKNOWN_FRAME",
116→          message: `Unknown query frame type: ${type}`,
117→        });
118→      });
119→  } catch (err) {
120→    sendFrame(connectionId, {
121→      type: "q:error",
122→      id: getFrameId(msg),
123→      code: "INVALID_FRAME",
124→      message: err instanceof Error ? err.message : "Invalid query frame",
125→    });
126→  }
127→}
128→
129→/** Remove all subscriptions for a connection (cleanup on disconnect). */
130→export function removeSubs(connectionId: string): void {
131→  const connSubs = subs.get(connectionId);
132→  if (connSubs) {
133→    for (const [subId, sub] of connSubs) {
134→      if (sub.resource === "messages") {
135→        messageCursors.delete(`${connectionId}:${subId}`);
136→      }
137→    }
138→    subs.delete(connectionId);
139→  }
140→}
141→
142→/** Optional context for targeted invalidation (e.g., which sessions changed). */
143→interface InvalidateContext {
144→  sessionIds?: string[];
145→}
146→
147→/**
148→ * Push-first invalidation: re-run queries for active subscribers and push
149→ * fresh snapshots or deltas.
150→ *
151→ * Messages use q:delta (cursor-based) instead of full snapshots.
152→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
153→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
154→ */
155→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
156→  if (resources.includes("stats")) {
157→    resetStatsCache();
158→  }
159→
160→  // Phase 1: Push fresh data to active subscribers
161→  for (const [connectionId, connSubs] of subs) {
162→    if (!getConnection(connectionId)) {
163→      removeSubs(connectionId);
164→      continue;
165→    }
166→
167→    for (const [subId, sub] of connSubs) {
168→      if (!resources.includes(sub.resource)) continue;
169→
170→      if (sub.resource === "messages") {
171→        // Messages: push delta (new messages since last cursor)
172→        pushMessageDelta(connectionId, subId, sub.params);
173→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
174→        // Workspaces with session context: try targeted delta
175→        try {
176→          const db = getDatabase();
177→          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
178→          const allowedStates = new Set(stateFilter.split(",").map(s => s.trim()));
179→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds)
180→            .filter(ws => allowedStates.has(ws.state));
181→          if (changedWorkspaces.length > 0) {
182→            const withPaths = changedWorkspaces.map(ws => ({
183→              ...ws,
184→              workspace_path: computeWorkspacePath(ws),
185→            }));
186→            sendFrame(connectionId, {
187→              type: "q:delta",
188→              id: subId,
189→              upserted: withPaths,
190→            });
191→          } else {
192→            // Session IDs didn't match any workspaces — fall back to full snapshot
193→            const data = runQuery(sub.resource, sub.params);
194→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
195→          }
196→        } catch (err) {
197→          // Delta lookup failed — fall back to full snapshot
198→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
199→          try {
200→            const data = runQuery(sub.resource, sub.params);
201→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
202→          } catch (snapErr) {
203→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
204→          }
205→        }
206→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
207→        // Session with context: only push if this subscription's session is in the changed set
208→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
209→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
210→          try {
211→            const data = runQuery(sub.resource, sub.params);
212→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
213→          } catch (err) {
214→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
215→          }
216→        }
217→        // If session not in changed set, skip the push
218→      } else {
219→        // Other resources: push full snapshot
220→        try {
221→          const data = runQuery(sub.resource, sub.params);
222→          sendFrame(connectionId, {
223→            type: "q:snapshot",
224→            id: subId,
225→            data,
226→          });
227→        } catch (err) {
228→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
229→        }
230→      }
231→    }
232→  }
233→
234→}
235→
236→// ---- Frame Handlers ----
237→
238→function handleRequest(connectionId: string, msg: ResourceFrameInput): void {
239→  const { id, resource, params } = msg;
240→
241→  try {
242→    const typedResource = toQueryResource(resource);
243→    const data = runQuery(typedResource, params);
244→    sendFrame(connectionId, { type: "q:response", id, data });
245→  } catch (err) {
246→    sendFrame(connectionId, {
247→      type: "q:error",
248→      id,
249→      code: "QUERY_ERROR",
250→      message: err instanceof Error ? err.message : "Query failed",
251→    });
252→  }
253→}
254→
255→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
256→  const { id, resource, params } = msg;
257→
258→  // Validate resource upfront — fail fast before running query
259→  const typedResource = toQueryResource(resource);
260→
261→  // Send initial snapshot — only register subscription if query succeeds
262→  // (avoids zombie subscriptions when runQuery throws on invalid params)
263→  try {
264→    const data = runQuery(typedResource, params);
265→
266→    // Get or create subscription map for this connection
267→    let connSubs = subs.get(connectionId);
268→    if (!connSubs) {
269→      connSubs = new Map();
270→      subs.set(connectionId, connSubs);
271→    }
272→
273→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
274→    connSubs.set(id, { id, resource: typedResource, params });
275→
276→    // For messages: initialize cursor to current max seq
277→    if (typedResource === "messages") {
278→      const sessionId = readStringParam(params, "sessionId");
279→      const cursorKey = `${connectionId}:${id}`;
280→      if (sessionId) {
281→        try {
282→          const db = getDatabase();
283→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
284→        } catch {
285→          messageCursors.set(cursorKey, 0);
286→        }
287→      }
288→    }
289→
290→    sendFrame(connectionId, { type: "q:snapshot", id, data });
291→  } catch (err) {
292→    sendFrame(connectionId, {
293→      type: "q:error",
294→      id,
295→      code: "SUBSCRIBE_ERROR",
296→      message: err instanceof Error ? err.message : "Subscribe failed",
297→    });
298→  }
299→}
300→
301→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
302→  const { id } = msg;
303→
304→  const connSubs = subs.get(connectionId);
305→  if (!connSubs) return;
306→
307→  const sub = connSubs.get(id);
308→  if (sub) {
309→    // Clean up message cursor
310→    if (sub.resource === "messages") {
311→      messageCursors.delete(`${connectionId}:${id}`);
312→    }
313→    connSubs.delete(id);
314→    if (connSubs.size === 0) subs.delete(connectionId);
315→  }
316→}
317→
318→function handleMutate(connectionId: string, msg: MutateFrameInput): void {
319→  const { id, action, params } = msg;
320→
321→  try {
322→    const result = runMutation(action, params);
323→    sendFrame(connectionId, {
324→      type: "q:mutate_result",
325→      id,
326→      success: true,
327→      data: result,
328→    });
329→  } catch (err) {
330→    sendFrame(connectionId, {
331→      type: "q:mutate_result",
332→      id,
333→      success: false,
334→      error: err instanceof Error ? err.message : "Mutation failed",
335→    });
336→  }
337→}
338→
339→function handleCommand(connectionId: string, msg: CommandFrameInput): void {
340→  const { id, command, params } = msg;
341→
342→  try {
343→    const result = runCommand(command, params);
344→    sendFrame(connectionId, {
345→      type: "q:command_ack",
346→      id,
347→      accepted: true,
348→      ...result,
349→    } satisfies QServerFrame);
350→  } catch (err) {
351→    sendFrame(connectionId, {
352→      type: "q:command_ack",
353→      id,
354→      accepted: false,
355→      error: err instanceof Error ? err.message : "Command failed",
356→    } satisfies QServerFrame);
357→  }
358→}
359→
360→// ---- Tool Response Handler ----
361→
362→function handleToolResponse(msg: QueryParams): void {
363→  const requestId = typeof msg.requestId === "string" ? msg.requestId : undefined;
364→  if (!requestId) {
365→    console.error("[QueryEngine] q:tool_response missing requestId");
366→    return;
367→  }
368→
369→  if (typeof msg.error === "string") {
370→    const resolved = rejectToolRelay(requestId, msg.error);
371→    if (!resolved) {
372→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (error)`);
373→    }
374→  } else {
375→    const resolved = resolveToolRelay(requestId, msg.result);
376→    if (!resolved) {
377→      console.warn(`[QueryEngine] q:tool_response for unknown requestId=${requestId} (result)`);
378→    }
379→  }
380→}
381→
382→// ---- Agent Forwarding ----
383→
384→type ForwardToAgentFn = (params: {
385→  sessionId: string;
386→  agentType: string;
387→  prompt: string;
388→  options: Record<string, unknown>;
389→}) => Promise<{ accepted: boolean; reason?: string }>;
390→
391→type CancelAgentFn = (params: { sessionId: string }) => Promise<void>;
392→
393→let forwardToAgent: ForwardToAgentFn | null = null;
394→let cancelAgent: CancelAgentFn | null = null;
395→
396→/** Register the agent client forwarding callbacks (called from server.ts) */
397→export function setAgentForwarder(forward: ForwardToAgentFn, cancel: CancelAgentFn): void {
398→  forwardToAgent = forward;
399→  cancelAgent = cancel;
400→}
401→
402→// ---- Command Dispatch ----
403→
404→function runCommand(command: string, params: QueryParams): { commandId?: string } {
405→  const typedCommand = toCommandName(command);
406→
407→  return match(typedCommand)
408→    .with("sendMessage", () => {
409→      const sessionId = readStringParam(params, "sessionId");
410→      const content = readStringParam(params, "content");
411→      const model = readStringParam(params, "model");
412→      if (!sessionId || !content) {
413→        throw new Error("sendMessage requires sessionId and content");
414→      }
415→
416→      const result = writeUserMessage(sessionId, content, model);
417→      if (!result.success) throw new Error(result.error);
418→      invalidate(["workspaces", "sessions", "session", "messages", "stats"], { sessionIds: [sessionId] });
419→
420→      // Forward to agent-server to start the turn
421→      if (forwardToAgent) {
422→        const agentType = readStringParam(params, "agentType") || "claude";
423→        forwardToAgent({
424→          sessionId,
425→          agentType,
426→          prompt: content,
427→          options: {
428→            cwd: readStringParam(params, "cwd") || "",
429→            model,
430→            maxThinkingTokens: params.maxThinkingTokens as number | undefined,
431→            maxTurns: params.maxTurns as number | undefined,
432→            turnId: readStringParam(params, "turnId"),
433→            permissionMode: readStringParam(params, "permissionMode"),
434→            claudeEnvVars: readStringParam(params, "claudeEnvVars"),
435→            ghToken: readStringParam(params, "ghToken"),
436→            opendevsEnv: params.opendevsEnv as Record<string, string> | undefined,
437→            additionalDirectories: params.additionalDirectories as string[] | undefined,
438→            chromeEnabled: params.chromeEnabled as boolean | undefined,
439→            strictDataPrivacy: params.strictDataPrivacy as boolean | undefined,
440→            shouldResetGenerator: params.shouldResetGenerator as boolean | undefined,
441→            resume: readStringParam(params, "resume"),
442→            resumeSessionAt: readStringParam(params, "resumeSessionAt"),
443→          },
444→        }).catch((err) => {
445→          console.error("[QueryEngine] Failed to forward to agent-server:", err);
446→        });
447→      }
448→
449→      return { commandId: result.messageId };
450→    })
451→    .with("stopSession", () => {
452→      const sessionId = readStringParam(params, "sessionId");
453→      if (!sessionId) throw new Error("stopSession requires sessionId");
454→
455→      // Forward cancel to agent-server
456→      if (cancelAgent) {
457→        cancelAgent({ sessionId }).catch((err) => {
458→          console.error("[QueryEngine] Failed to cancel on agent-server:", err);
459→        });
460→      }
461→
462→      const db = getDatabase();
463→      const session = getSessionRaw(db, sessionId);
464→      if (!session) throw new Error("Session not found");
465→
466→      db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(sessionId);
467→      invalidate(["workspaces", "sessions", "session", "stats"], { sessionIds: [sessionId] });
468→      return {};
469→    })
470→    .exhaustive();
471→}
472→
473→// ---- Query Dispatch ----
474→
475→function runQuery(resource: QueryResource, params: QueryParams): unknown {
476→  const db = getDatabase();
477→
478→  return match(resource)
479→    .with("workspaces", () => {
480→      // Return RepoGroup[] shape matching GET /workspaces/by-repo
481→      const state = readStringParam(params, "state") ?? "ready,initializing";
482→      const workspaces = getWorkspacesByRepo(db, state);
483→
484→      const grouped: Record<string, { repo_id: string; repo_name: string; sort_order: number; workspaces: unknown[] }> = {};
485→      workspaces.forEach(workspace => {
486→        const repoId = workspace.repository_id || "unknown";
487→        if (!grouped[repoId]) {
488→          grouped[repoId] = {
489→            repo_id: repoId,
490→            repo_name: workspace.repo_name || "Unknown",
491→            sort_order: workspace.repo_sort_order ?? 999,
492→            workspaces: [],
493→          };
494→        }
495→        grouped[repoId].workspaces.push({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
496→      });
497→
498→      // Backfill repos that have no matching workspaces (e.g. all archived)
499→      const allRepos = getAllRepositorySummaries(db);
500→      for (const repo of allRepos) {
501→        if (!grouped[repo.id]) {
502→          grouped[repo.id] = {
503→            repo_id: repo.id,
504→            repo_name: repo.name,
505→            sort_order: repo.sort_order ?? 999,
506→            workspaces: [],
507→          };
508→        }
509→      }
510→
511→      return Object.values(grouped).sort((a, b) => a.sort_order - b.sort_order);
512→    })
513→    .with("stats", () => getStats(db))
514→    .with("sessions", () => {
515→      const workspaceId = readStringParam(params, "workspaceId");
516→      if (!workspaceId) throw new Error("sessions requires workspaceId param");
517→      return getSessionsByWorkspaceId(db, workspaceId);
518→    })
519→    .with("session", () => {
520→      const sessionId = readStringParam(params, "sessionId");
521→      if (!sessionId) throw new Error("session requires sessionId param");
522→      return getSessionById(db, sessionId);
523→    })
524→    .with("messages", () => {
525→      const sessionId = readStringParam(params, "sessionId");
526→      if (!sessionId) throw new Error("messages requires sessionId param");
527→
528→      const rows = getMessages(db, sessionId, {
529→        limit: readNumberParam(params, "limit") ?? 50,
530→        before: readNumberParam(params, "before"),
531→        after: readNumberParam(params, "after"),
532→      });
533→
534→      const hasOlder = rows.length > 0 ? hasOlderMessages(db, sessionId, rows[0].seq) : false;
535→      const hasNewer = rows.length > 0
536→        ? hasNewerMessages(db, sessionId, rows[rows.length - 1].seq)
537→        : false;
538→
539→      return { messages: rows, has_older: hasOlder, has_newer: hasNewer };
540→    })
541→    .exhaustive();
542→}
543→
544→// ---- Mutation Dispatch ----
545→
546→function runMutation(action: string, params: QueryParams): unknown {
547→  const typedAction = toMutationName(action);
548→
549→  return match(typedAction)
550→    .with("archiveWorkspace", () => {
551→      const db = getDatabase();
552→      const workspaceId = readStringParam(params, "workspaceId");
553→      if (!workspaceId) throw new Error("archiveWorkspace requires workspaceId");
554→
555→      const workspace = getWorkspaceRaw(db, workspaceId);
556→      if (!workspace) throw new Error("Workspace not found");
557→
558→      db.prepare("UPDATE workspaces SET state = 'archived' WHERE id = ?").run(workspaceId);
559→      invalidate(["workspaces", "stats"]);
560→      return { success: true };
561→    })
562→    .with("updateWorkspaceTitle", () => {
563→      const db = getDatabase();
564→      const workspaceId = readStringParam(params, "workspaceId");
565→      const title = readStringParam(params, "title");
566→      if (!workspaceId || title === undefined) {
567→        throw new Error("updateWorkspaceTitle requires workspaceId and title");
568→      }
569→
570→      const workspace = getWorkspaceRaw(db, workspaceId);
571→      if (!workspace) throw new Error("Workspace not found");
572→
573→      db.prepare("UPDATE workspaces SET title = ? WHERE id = ?").run(title, workspaceId);
574→      invalidate(["workspaces"]);
575→      return { success: true };
576→    })
577→    .exhaustive();
578→}
579→
580→// ---- Message Delta Push ----
581→
582→function pushMessageDelta(connectionId: string, subId: string, params: QueryParams): void {
583→  const sessionId = readStringParam(params, "sessionId");
584→  if (!sessionId) return;
585→
586→  const cursorKey = `${connectionId}:${subId}`;
587→  const lastSeq = messageCursors.get(cursorKey) ?? 0;
588→
589→  try {
590→    const db = getDatabase();
591→    const newMessages = getMessagesDelta(db, sessionId, lastSeq);
592→
593→    if (newMessages.length === 0) return;
594→
595→    const maxSeq = newMessages[newMessages.length - 1].seq;
596→    messageCursors.set(cursorKey, maxSeq);
597→
598→    sendFrame(connectionId, {
599→      type: "q:delta",
600→      id: subId,
601→      upserted: newMessages,
602→      cursor: maxSeq,
603→    });
604→  } catch (err) {
605→    console.error(`[QueryEngine] Message delta push failed:`, err);
606→  }
607→}
608→
609→// ---- Helpers ----
610→
611→function sendFrame(connectionId: string, frame: QServerFrame): void {
612→  const conn = getConnection(connectionId);
613→  if (!conn) return;
614→  try {
615→    conn.ws.send(JSON.stringify(frame));
616→  } catch {
617→    // Connection may have closed
618→  }
619→}
620→
621→function parseResourceFrame(msg: QueryParams): ResourceFrameInput {
622→  return {
623→    id: requireString(msg.id, "id"),
624→    resource: requireString(msg.resource, "resource"),
625→    params: getParams(msg.params),
626→  };
627→}
628→
629→function parseUnsubscribeFrame(msg: QueryParams): UnsubscribeFrameInput {
630→  return {
631→    id: requireString(msg.id, "id"),
632→  };
633→}
634→
635→function parseMutateFrame(msg: QueryParams): MutateFrameInput {
636→  return {
637→    id: requireString(msg.id, "id"),
638→    action: requireString(msg.action, "action"),
639→    params: getParams(msg.params),
640→  };
641→}
642→
643→function getParams(value: unknown): QueryParams {
644→  if (value == null) return {};
645→  if (isRecord(value)) return value;
646→  throw new Error("Frame params must be an object");
647→}
648→
649→function requireString(value: unknown, field: string): string {
650→  if (typeof value !== "string") {
651→    throw new Error(`Frame requires string ${field}`);
652→  }
653→  return value;
654→}
655→
656→function getFrameId(msg: QueryParams): string {
657→  return typeof msg.id === "string" ? msg.id : "unknown";
658→}
659→
660→function isRecord(value: unknown): value is QueryParams {
661→  return typeof value === "object" && value !== null && !Array.isArray(value);
662→}
663→
664→function readStringParam(params: QueryParams, key: string): string | undefined {
665→  const value = params[key];
666→  return typeof value === "string" ? value : undefined;
667→}
668→
669→function readNumberParam(params: QueryParams, key: string): number | undefined {
670→  const value = params[key];
671→  return typeof value === "number" ? value : undefined;
672→}
673→
674→function isQueryResource(value: string): value is QueryResource {
675→  return (QUERY_RESOURCES as readonly string[]).includes(value);
676→}
677→
678→function toQueryResource(value: string): QueryResource {
679→  if (!isQueryResource(value)) throw new Error(`Unknown resource: ${value}`);
680→  return value;
681→}
682→
683→function isMutationName(value: string): value is MutationName {
684→  return (MUTATION_NAMES as readonly string[]).includes(value);
685→}
686→
687→function toMutationName(value: string): MutationName {
688→  if (!isMutationName(value)) throw new Error(`Unknown mutation: ${value}`);
689→  return value;
690→}
691→
692→function parseCommandFrame(msg: QueryParams): CommandFrameInput {
693→  return {
694→    id: requireString(msg.id, "id"),
695→    command: requireString(msg.command, "command"),
696→    params: getParams(msg.params),
697→  };
698→}
699→
700→function isCommandName(value: string): value is CommandName {
701→  return (COMMAND_NAMES as readonly string[]).includes(value);
702→}
703→
704→function toCommandName(value: string): CommandName {
705→  if (!isCommandName(value)) throw new Error(`Unknown command: ${value}`);
706→  return value;
707→}
