150→// ============================================================================
151→// EventBroadcaster class
152→// ============================================================================
153→
154→class EventBroadcasterClass {
155→  // Multi-tunnel: all connected clients receive notifications.
156→  // The relay and desktop app can be connected simultaneously.
157→  private tunnels = new Set<RpcConnection>();
158→
159→  attachTunnel(tunnel: RpcConnection): void {
160→    this.tunnels.add(tunnel);
161→    console.log(`[EventBroadcaster] Tunnel attached (${this.tunnels.size} active)`);
162→  }
163→
164→  /**
165→   * Detach a specific tunnel. If tunnel is provided, removes only that one.
166→   * If no tunnel is provided, clears all tunnels.
167→   */
168→  detachTunnel(tunnel?: RpcConnection): void {
169→    if (tunnel) {
170→      this.tunnels.delete(tunnel);
171→      console.log(`[EventBroadcaster] Tunnel detached (${this.tunnels.size} remaining)`);
172→    } else {
173→      this.tunnels.clear();
174→      console.log("[EventBroadcaster] All tunnels cleared");
175→    }
176→  }
177→
178→  // ==========================================================================
179→  // OUTGOING NOTIFICATIONS (sidecar -> frontend)
180→  // ==========================================================================
181→
182→  sendMessage(response: MessageResponse): void {
183→    this.broadcastNotification(FRONTEND_NOTIFICATIONS.MESSAGE, response, "sendMessage");
184→  }
185→
186→  sendError(response: ErrorResponse): void {
187→    this.broadcastNotification(FRONTEND_NOTIFICATIONS.QUERY_ERROR, response, "sendError");
188→  }
189→
190→  sendEnterPlanModeNotification(response: EnterPlanModeNotification): void {
191→    this.broadcastNotification(
192→      FRONTEND_NOTIFICATIONS.ENTER_PLAN_MODE,
193→      response,
194→      "sendEnterPlanModeNotification"
195→    );
196→  }
197→
198→  sendStatusChanged(notification: StatusChangedNotification): void {
199→    this.broadcastNotification(
200→      FRONTEND_NOTIFICATIONS.STATUS_CHANGED,
201→      notification,
202→      "sendStatusChanged"
203→    );
204→  }
205→
206→  // ==========================================================================
207→  // CANONICAL EVENT EMISSION (agent-server protocol — dual-write period)
208→  //
209→  // These methods emit provider-neutral events defined in shared/agent-events.ts
210→  // as JSON-RPC notifications to all connected tunnels. During the dual-write
211→  // period, both the old notifications (sendMessage/sendError/etc.) and these
212→  // canonical events are emitted simultaneously.
213→  // ==========================================================================
214→
215→  /** Generic emit: broadcasts a canonical AgentEvent as a JSON-RPC notification. */
216→  emitEvent(event: AgentEvent): void {
217→    this.broadcastNotification(event.type, event, `emitEvent(${event.type})`);
218→  }
219→
220→  // --- Session lifecycle ---
221→
222→  emitSessionStarted(sessionId: string, agentType: AgentType): void {
223→    this.emitEvent({
224→      type: AGENT_EVENT_NAMES.SESSION_STARTED,
225→      sessionId,
226→      agentType,
227→    });
228→  }
229→
230→  emitSessionIdle(sessionId: string, agentType: AgentType): void {
231→    this.emitEvent({
232→      type: AGENT_EVENT_NAMES.SESSION_IDLE,
233→      sessionId,
234→      agentType,
235→    });
236→  }
237→
238→  emitSessionError(
239→    sessionId: string,
240→    agentType: AgentType,
241→    error: string,
242→    category: ErrorCategory
243→  ): void {
244→    this.emitEvent({
245→      type: AGENT_EVENT_NAMES.SESSION_ERROR,
246→      sessionId,
247→      agentType,
248→      error,
249→      category,
250→    });
251→  }
252→
253→  emitSessionCancelled(sessionId: string, agentType: AgentType): void {
254→    this.emitEvent({
255→      type: AGENT_EVENT_NAMES.SESSION_CANCELLED,
256→      sessionId,
257→      agentType,
258→    });
259→  }
260→
261→  // --- Messages ---
262→
263→  emitAssistantMessage(
264→    sessionId: string,
265→    agentType: AgentType,
266→    message: {
267→      id: string;
268→      role: "assistant";
269→      content: unknown;
270→      stop_reason?: string | null;
271→      parent_tool_use_id?: string | null;
272→    },
273→    model?: string
274→  ): void {
275→    this.emitEvent({
276→      type: AGENT_EVENT_NAMES.MESSAGE_ASSISTANT,
277→      sessionId,
278→      agentType,
279→      message,
280→      ...(model ? { model } : {}),
281→    });
282→  }
283→
284→  emitToolResultMessage(
285→    sessionId: string,
286→    agentType: AgentType,
287→    message: { id: string; role: "user"; content: unknown; parent_tool_use_id?: string | null },
288→    model?: string
