  1→// backend/src/services/agent-client.ts
  2→// WebSocket client that connects to the agent-server (sidecar).
  3→//
  4→// Implements the JSON-RPC 2.0 handshake protocol:
  5→//   Backend → Agent: { method: "initialize", params: { version: "1.0", capabilities: {} } }
  6→//   Agent → Backend: { result: { version: "1.0", agents: [...], capabilities: {} } }
  7→//   Backend → Agent: { method: "initialized" } (notification)
  8→//
  9→// After handshake, exposes typed methods for turn lifecycle and listens for
 10→// canonical agent-event notifications.
 11→
 12→import { WebSocket } from "ws";
 13→import {
 14→  JSONRPCServer,
 15→  JSONRPCClient,
 16→  JSONRPCServerAndClient,
 17→  isJSONRPCRequest,
 18→  isJSONRPCRequests,
 19→  isJSONRPCResponse,
 20→  isJSONRPCResponses,
 21→} from "json-rpc-2.0";
 22→import {
 23→  AGENT_RPC_METHODS,
 24→  AGENT_EVENT_NAMES,
 25→  AgentEventSchema,
 26→  InitializeResultSchema,
 27→  type InitializeResult,
 28→  type TurnStartRequest,
 29→  type TurnStartResponse,
 30→  type TurnCancelRequest,
 31→  type TurnRespondRequest,
 32→  type SessionResetRequest,
 33→  type SessionStopRequest,
 34→  type ProviderAuthRequest,
 35→  type ProviderInitWorkspaceRequest,
 36→  type ProviderContextUsageRequest,
 37→  type ProviderUpdateModeRequest,
 38→  type AgentEvent,
 39→  type AgentInfo,
 40→} from "../../../shared/agent-events";
 41→
 42→// ============================================================================
 43→// Types
 44→// ============================================================================
 45→
 46→export type AgentEventHandler = (event: AgentEvent) => void;
 47→
 48→export interface AgentClientOptions {
 49→  /** ws://127.0.0.1:{port} — the agent-server URL */
 50→  url: string;
 51→  /** Called for every canonical agent-event notification received from the agent-server */
 52→  onEvent?: AgentEventHandler;
 53→  /** Called when the connection is established and handshake completes */
 54→  onConnected?: (agents: AgentInfo[]) => void;
 55→  /** Called when the connection drops */
 56→  onDisconnected?: () => void;
 57→}
 58→
 59→// ============================================================================
 60→// Reconnect constants
 61→// ============================================================================
 62→
 63→const BASE_RECONNECT_DELAY_MS = 1_000;
 64→const MAX_RECONNECT_DELAY_MS = 30_000;
 65→const HANDSHAKE_TIMEOUT_MS = 10_000;
 66→const PROTOCOL_VERSION = "1.0";
 67→
 68→// ============================================================================
 69→// AgentClient
 70→// ============================================================================
 71→
 72→export class AgentClient {
 73→  private url: string;
 74→  private ws: WebSocket | null = null;
 75→  private peer: JSONRPCServerAndClient | null = null;
 76→  private onEvent: AgentEventHandler;
 77→  private onConnected?: (agents: AgentInfo[]) => void;
 78→  private onDisconnected?: () => void;
 79→
 80→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 81→  private reconnectAttempt = 0;
 82→  private disposed = false;
 83→  private connected = false;
 84→
 85→  /** Agents discovered during the initialize handshake */
 86→  private agents: AgentInfo[] = [];
 87→
 88→  constructor(options: AgentClientOptions) {
 89→    this.url = options.url;
 90→    this.onEvent = options.onEvent ?? (() => {});
 91→    this.onConnected = options.onConnected;
 92→    this.onDisconnected = options.onDisconnected;
 93→  }
 94→
 95→  // ==========================================================================
 96→  // Public API
 97→  // ==========================================================================
 98→
 99→  /** Initiate connection to the agent-server. Auto-reconnects on drop. */
100→  connect(): void {
101→    if (this.disposed) return;
102→    if (this.ws && this.ws.readyState !== WebSocket.CLOSED) {
103→      return;
104→    }
105→    this.cancelReconnect();
106→    this.openConnection();
107→  }
108→
109→  /** Permanently disconnect and stop reconnecting. */
110→  disconnect(): void {
111→    this.disposed = true;
112→    this.cancelReconnect();
113→    this.closeConnection();
114→  }
115→
116→  /** Returns true if the handshake is complete and the connection is open. */
117→  isConnected(): boolean {
118→    return this.connected && this.ws?.readyState === WebSocket.OPEN;
119→  }
120→
121→  /** Returns the agents discovered during handshake. */
122→  getAgents(): ReadonlyArray<AgentInfo> {
123→    return this.agents;
124→  }
125→
126→  // ---- Turn lifecycle RPCs ----
127→
128→  async sendTurnStart(params: TurnStartRequest): Promise<TurnStartResponse> {
129→    return this.request(AGENT_RPC_METHODS.TURN_START, params) as Promise<TurnStartResponse>;
130→  }
131→
132→  async sendTurnCancel(params: TurnCancelRequest): Promise<void> {
133→    await this.request(AGENT_RPC_METHODS.TURN_CANCEL, params);
134→  }
135→
136→  async sendTurnRespond(params: TurnRespondRequest): Promise<void> {
137→    await this.request(AGENT_RPC_METHODS.TURN_RESPOND, params);
138→  }
139→
140→  // ---- Session lifecycle RPCs ----
141→
142→  async sendSessionReset(params: SessionResetRequest): Promise<void> {
143→    await this.request(AGENT_RPC_METHODS.SESSION_RESET, params);
144→  }
145→
146→  async sendSessionStop(params: SessionStopRequest): Promise<void> {
147→    await this.request(AGENT_RPC_METHODS.SESSION_STOP, params);
148→  }
149→
150→  // ---- Provider operations ----
151→
152→  async sendProviderAuth(params: ProviderAuthRequest): Promise<unknown> {
153→    return this.request(AGENT_RPC_METHODS.PROVIDER_AUTH, params);
154→  }
155→
156→  async sendProviderInitWorkspace(params: ProviderInitWorkspaceRequest): Promise<unknown> {
157→    return this.request(AGENT_RPC_METHODS.PROVIDER_INIT_WORKSPACE, params);
158→  }
159→
160→  async sendProviderContextUsage(params: ProviderContextUsageRequest): Promise<unknown> {
161→    return this.request(AGENT_RPC_METHODS.PROVIDER_CONTEXT_USAGE, params);
162→  }
163→
164→  async sendProviderUpdateMode(params: ProviderUpdateModeRequest): Promise<void> {
165→    this.notify(AGENT_RPC_METHODS.PROVIDER_UPDATE_MODE, params);
166→  }
167→
168→  // ---- Introspection ----
169→
170→  async listAgents(): Promise<AgentInfo[]> {
171→    const result = await this.request(AGENT_RPC_METHODS.AGENT_LIST, {});
172→    return (result as any)?.agents ?? [];
173→  }
174→
175→  // ==========================================================================
176→  // Connection lifecycle
177→  // ==========================================================================
178→
179→  private openConnection(): void {
180→    if (this.disposed) return;
181→
182→    console.log(`[AgentClient] Connecting to ${this.url}...`);
183→
184→    try {
185→      this.ws = new WebSocket(this.url);
186→    } catch (err) {
187→      console.error("[AgentClient] Failed to create WebSocket:", err);
188→      this.scheduleReconnect();
189→      return;
190→    }
191→
192→    this.ws.on("open", () => {
193→      console.log("[AgentClient] WebSocket connected, starting handshake...");
194→      this.reconnectAttempt = 0;
195→      this.setupPeer();
196→      void this.performHandshake();
197→    });
198→
199→    this.ws.on("message", (data: Buffer | string) => {
200→      const message = typeof data === "string" ? data : data.toString("utf8");
201→      this.handleMessage(message);
202→    });
203→
204→    this.ws.on("close", (code, reason) => {
205→      console.log(`[AgentClient] Connection closed: ${code} ${reason.toString()}`);
206→      this.teardownPeer();
207→      if (!this.disposed) this.scheduleReconnect();
208→    });
209→
210→    this.ws.on("error", (err) => {
211→      console.error("[AgentClient] WebSocket error:", err.message);
212→    });
213→  }
214→
215→  private closeConnection(): void {
216→    if (this.ws) {
217→      this.ws.removeAllListeners();
218→      if (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING) {
219→        this.ws.close(1000, "Client disconnecting");
220→      }
221→      this.ws = null;
222→    }
223→    this.teardownPeer();
224→  }
225→
226→  // ==========================================================================
227→  // JSON-RPC peer
228→  // ==========================================================================
229→
230→  private setupPeer(): void {
231→    const server = new JSONRPCServer({
232→      errorListener: (message, data) => {
233→        console.error("[AgentClient] RPC server error:", message, data);
234→      },
235→    });
236→
237→    const client = new JSONRPCClient((payload) => {
238→      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
239→        return Promise.reject(new Error("WebSocket is not open"));
240→      }
241→      try {
242→        this.ws.send(JSON.stringify(payload));
243→        return Promise.resolve();
244→      } catch (error) {
245→        return Promise.reject(error instanceof Error ? error : new Error(String(error)));
246→      }
247→    });
248→
249→    this.peer = new JSONRPCServerAndClient(server, client, {
250→      errorListener: (message, data) => {
251→        console.error("[AgentClient] RPC client error:", message, data);
252→      },
253→    });
254→
255→    // Register handlers for all agent-event notification methods.
256→    // The agent-server sends these as JSON-RPC notifications (no id).
257→    for (const eventName of Object.values(AGENT_EVENT_NAMES)) {
258→      this.peer.addMethod(eventName, async (params) => {
259→        this.dispatchEvent(eventName, params);
260→        return undefined; // notifications don't return a value
261→      });
262→    }
263→  }
264→
265→  private teardownPeer(): void {
266→    const wasConnected = this.connected;
267→    this.connected = false;
268→    if (this.peer) {
269→      this.peer.rejectAllPendingRequests("Connection closed");
270→      this.peer = null;
271→    }
272→    if (wasConnected) {
273→      this.onDisconnected?.();
274→    }
275→  }
276→
277→  private dispatchEvent(eventName: string, params: unknown): void {
278→    // Validate and normalize the event payload using the canonical schema.
279→    // If parsing fails, log and skip — don't crash the client.
280→    const parsed = AgentEventSchema.safeParse(params);
281→    if (!parsed.success) {
282→      console.error(`[AgentClient] Invalid event payload for "${eventName}":`, parsed.error.message);
283→      return;
284→    }
285→    try {
286→      this.onEvent(parsed.data);
287→    } catch (err) {
288→      console.error(`[AgentClient] Event handler threw for "${eventName}":`, err);
289→    }
290→  }
291→
292→  // ==========================================================================
293→  // Handshake
