  1→/**
  2→ * Session Query Hooks
  3→ * TanStack Query hooks for Claude Code session management
  4→ */
  5→
  6→import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
  7→import { produce } from "immer";
  8→import { SessionService } from "./session.service";
  9→import type { PaginatedMessages } from "./session.service";
 10→import { queryKeys } from "@/shared/api/queryKeys";
 11→import { useQuerySubscription } from "@/shared/hooks/useQuerySubscription";
 12→import {
 13→  MESSAGE_PAGE_SIZE,
 14→  INITIAL_MESSAGE_PAGE_SIZE,
 15→  mergeMessageDelta,
 16→} from "../lib/messageCache";
 17→import type { ContentBlock, Message, Session, SessionStatus } from "../types";
 18→import { isToolResultBlock } from "../types";
 19→import type { RepoGroup } from "@shared/types/workspace";
 20→import { useMemo, useCallback } from "react";
 21→import { track } from "@/platform/analytics";
 22→import { parseContentBlocks } from "../lib/contentParser";
 23→import { sendCommand, connect, isConnected } from "@/platform/ws";
 24→import type { RuntimeAgentType } from "../lib/agentRuntime";
 25→
 26→/**
 27→ * Fetch all sessions for a workspace (used by chat tab reconstruction).
 28→ * Stale time is high — tabs only hydrate on mount and after creating new sessions.
 29→ */
 30→export function useWorkspaceSessions(workspaceId: string | null) {
 31→  useQuerySubscription("sessions", {
 32→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 33→    params: { workspaceId: workspaceId || "" },
 34→    enabled: !!workspaceId,
 35→  });
 36→
 37→  return useQuery({
 38→    queryKey: queryKeys.sessions.byWorkspace(workspaceId || ""),
 39→    queryFn: () => SessionService.fetchByWorkspace(workspaceId!),
 40→    enabled: !!workspaceId,
 41→    staleTime: Infinity,
 42→    refetchOnWindowFocus: false,
 43→  });
 44→}
 45→
 46→/**
 47→ * Fetch session details — fully WS-driven, no polling.
 48→ *
 49→ * Updates come from WS subscription: backend pushes q:snapshot on
 50→ * session:status, session:updated, and session:message notifications.
 51→ * HTTP queryFn is fallback for initial load before WS connects.
 52→ */
 53→export function useSession(sessionId: string | null) {
 54→  useQuerySubscription("session", {
 55→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 56→    params: { sessionId: sessionId || "" },
 57→    enabled: !!sessionId,
 58→  });
 59→
 60→  return useQuery({
 61→    queryKey: queryKeys.sessions.detail(sessionId || ""),
 62→    queryFn: () => SessionService.fetchById(sessionId!),
 63→    enabled: !!sessionId,
 64→    staleTime: Infinity,
 65→    refetchOnWindowFocus: false,
 66→  });
 67→}
 68→
 69→/**
 70→ * Subscribe to per-session working status for multiple sessions at once.
 71→ * Used by the tab bar to show per-tab spinners correctly.
 72→ *
 73→ * The workspace's single `session_status` field breaks with multiple tabs —
 74→ * it gets overwritten by whichever session's event fires last. This hook
 75→ * subscribes to each session's detail cache reactively so tab spinners
 76→ * reflect each session's actual status.
 77→ *
 78→ * No extra HTTP fetches when data is already in cache (populated by
 79→ * the "session" WS subscription via q:snapshot on status changes).
 80→ */
 81→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 82→  const queries = useQueries({
 83→    queries: sessionIds.map((id) => ({
 84→      queryKey: queryKeys.sessions.detail(id),
 85→      queryFn: () => SessionService.fetchById(id),
 86→      staleTime: 30_000,
 87→      select: (data: Session): SessionStatus => data.status,
 88→    })),
 89→  });
 90→
 91→  // Derive working IDs from query results. useMemo deps use `queries`
 92→  // directly — React Compiler requires it. The select: data.status
 93→  // ensures queries only change identity when a status actually changes.
 94→  return useMemo(() => {
 95→    const ids = new Set<string>();
 96→    sessionIds.forEach((id, i) => {
 97→      if (queries[i]?.data === "working") ids.add(id);
 98→    });
 99→    return ids;
100→  }, [queries, sessionIds]);
101→}
102→
103→/**
104→ * Fetch messages for a session — fully WS-driven.
105→ *
106→ * WS subscription pushes q:delta frames with new messages since last cursor.
107→ * mergeMessageDelta handles the PaginatedMessages shape, deduplication,
108→ * and optimistic placeholder cleanup.
109→ * HTTP queryFn is fallback for initial load before WS connects.
110→ */
111→export function useMessages(sessionId: string | null) {
112→  useQuerySubscription("messages", {
113→    queryKey: queryKeys.sessions.messages(sessionId || ""),
114→    params: { sessionId: sessionId || "" },
115→    enabled: !!sessionId,
116→    mergeDelta: mergeMessageDelta,
117→  });
118→
119→  const query = useQuery({
120→    queryKey: queryKeys.sessions.messages(sessionId || ""),
121→    queryFn: () => SessionService.fetchMessages(sessionId!, { limit: INITIAL_MESSAGE_PAGE_SIZE }),
122→    enabled: !!sessionId,
123→    refetchInterval: false,
124→    staleTime: Infinity,
125→    refetchOnWindowFocus: false,
126→  });
127→
128→  return query;
129→}
130→
131→/**
132→ * Combined hook for session + messages + status
133→ * Replaces the complex useMessages hook
134→ */
135→export function useSessionWithMessages(sessionId: string | null) {
136→  const sessionQuery = useSession(sessionId);
137→  const messagesQuery = useMessages(sessionId);
138→
139→  // Unwrap messages from PaginatedMessages (select was removed to expose has_older)
140→  const messages = messagesQuery.data?.messages ?? [];
141→  const hasOlder = messagesQuery.data?.has_older ?? false;
142→
143→  // Parse content helper — delegates to pure function in lib/contentParser.ts
144→  // Memoized to prevent Context cascade re-renders
145→  const parseContent = useCallback(
146→    (content: string): (ContentBlock | string)[] | string => parseContentBlocks(content),
147→    []
148→  );
149→
150→  // Build tool result map and parent_tool_use_id map in a single pass.
151→  const { toolResultMap, parentToolUseMap } = useMemo(() => {
152→    const resultMap = new Map();
153→    const parentMap = new Map<string, string>();
154→    if (!messages.length) return { toolResultMap: resultMap, parentToolUseMap: parentMap };
155→
156→    messages.forEach((msg: Message) => {
157→      if (msg.parent_tool_use_id) {
158→        parentMap.set(msg.id, msg.parent_tool_use_id);
159→      }
160→
161→      const blocks = parseContent(msg.content);
162→      if (Array.isArray(blocks)) {
163→        blocks.filter(isToolResultBlock).forEach((block) => {
164→          resultMap.set(block.tool_use_id, block);
165→        });
166→      }
167→    });
168→
169→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
170→  }, [messages, parseContent]);
171→
172→  // Group subagent messages by their parent Task tool_use_id
173→  const subagentMessages = useMemo(() => {
174→    const map = new Map<string, Message[]>();
175→    if (!messages.length) return map;
176→
177→    messages.forEach((msg: Message) => {
178→      const parentId = parentToolUseMap.get(msg.id);
179→      if (parentId) {
180→        if (!map.has(parentId)) map.set(parentId, []);
181→        map.get(parentId)!.push(msg);
182→      }
183→    });
184→
185→    return map;
186→  }, [messages, parentToolUseMap]);
187→
188→  // Get latest user message's sent_at for duration tracking
189→  const latestMessageSentAt = useMemo(() => {
190→    if (!messages.length) return null;
191→
192→    // Find the latest user message
193→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
194→
195→    return latestUserMessage?.sent_at || null;
196→  }, [messages]);
197→
198→  return {
199→    session: sessionQuery.data,
200→    messages,
201→    hasOlder,
202→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
203→    latestMessageSentAt,
204→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
205→    error: sessionQuery.error || messagesQuery.error,
206→    parseContent,
207→    toolResultMap,
208→    parentToolUseMap,
209→    subagentMessages,
210→  };
211→}
212→
213→/**
214→ * Load older messages (scroll-up pagination).
215→ * Prepends older messages to the cache while preserving has_newer from current cache.
216→ */
217→export function useLoadOlderMessages() {
218→  const queryClient = useQueryClient();
219→
220→  return useMutation({
221→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
222→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
223→
224→    onSuccess: (olderPage, { sessionId }) => {
225→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
226→        if (!old) return olderPage;
227→        // Deduplicate by id (shouldn't happen, but safety first)
228→        const existingIds = new Set(old.messages.map((m) => m.id));
229→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
230→        return {
231→          messages: [...newMessages, ...old.messages],
232→          has_older: olderPage.has_older,
233→          has_newer: old.has_newer,
234→        };
235→      });
236→    },
237→  });
238→}
239→
240→/**
241→ * Send message mutation with optimistic update
242→ *
243→ * Shows user message immediately in the chat while request is in flight.
244→ * The optimistic message has a temporary ID that gets replaced on refetch.
245→ */
246→export function useSendMessage() {
247→  const queryClient = useQueryClient();
248→
249→  return useMutation({
250→    mutationFn: async ({
251→      sessionId,
252→      content,
253→      model,
254→      cwd,
255→      agentType,
256→    }: {
257→      sessionId: string;
258→      content: string;
259→      model?: string;
260→      cwd?: string;
261→      agentType?: RuntimeAgentType;
262→    }): Promise<Message | void> => {
263→      // Send message via WS command: backend saves user message to DB,
264→      // forwards to agent-server, and pushes q:delta to subscribers.
265→      if (cwd) {
266→        if (!isConnected()) await connect();
267→        const ack = await sendCommand("sendMessage", {
268→          sessionId,
269→          content,
270→          model,
271→          cwd,
272→          agentType: agentType || "claude",
273→        });
274→        if (!ack.accepted) {
275→          throw new Error(ack.error || "Agent rejected the query");
276→        }
277→        // No return value needed — WS q:delta handles message reconciliation.
278→        return;
279→      }
280→      // Gateway/web fallback: HTTP POST to backend
281→      return SessionService.sendMessage(sessionId, content, model);
282→    },
283→
284→    // Optimistic update: show user message immediately.
285→    // Status indicators (tab spinner, sidebar) are updated by the workspaces
286→    // WS subscription — the sidecar notifies the backend, which pushes fresh
287→    // workspace snapshots within ~50ms.
288→    onMutate: async ({ sessionId, content, model }) => {
289→      await queryClient.cancelQueries({
290→        queryKey: queryKeys.sessions.messages(sessionId),
291→      });
292→
293→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
294→        queryKeys.sessions.messages(sessionId)
295→      );
296→
297→      // Snapshot workspace-by-repo cache before optimistic update so we can
298→      // restore the exact prior status on error (instead of hardcoding "idle").
299→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
300→        queryKey: ["workspaces", "by-repo"],
301→      });
302→
303→      // Create optimistic user message
304→      const optimisticId =
305→        typeof crypto !== "undefined" && "randomUUID" in crypto
306→          ? `optimistic-${crypto.randomUUID()}`
307→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
308→
309→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
310→      let optimisticContentJson: string;
311→      try {
312→        const parsed = JSON.parse(content);
313→        if (Array.isArray(parsed)) {
314→          optimisticContentJson = JSON.stringify(parsed);
315→        } else {
316→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
317→        }
318→      } catch {
319→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
320→      }
321→
322→      const optimisticMessage: Message = {
323→        id: optimisticId,
324→        session_id: sessionId,
325→        seq: Number.MAX_SAFE_INTEGER,
326→        role: "user",
327→        content: optimisticContentJson,
328→        sent_at: new Date().toISOString(),
329→        model: model ?? null,
330→      };
331→
332→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
333→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
334→        return produce(old, (draft) => {
335→          draft.messages.push(optimisticMessage);
336→        });
337→      });
338→
339→      // Optimistically set workspace status to "working" in sidebar cache.
340→      // Handles the startup race where the first Tauri event arrives before
341→      // the workspace list has loaded (cache empty → event matching fails).
342→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
343→        if (!old) return old;
344→        return old.map((group) => ({
345→          ...group,
346→          workspaces: group.workspaces.map((ws) =>
347→            ws.current_session_id === sessionId
348→              ? { ...ws, session_status: "working" as SessionStatus }
349→              : ws
350→          ),
351→        }));
352→      });
353→
354→      return { previousMessages, previousWorkspaceByRepo };
355→    },
356→
357→    onError: (_err, variables, context) => {
358→      // Roll back optimistic message
359→      if (context?.previousMessages) {
360→        queryClient.setQueryData(
361→          queryKeys.sessions.messages(variables.sessionId),
362→          context.previousMessages
363→        );
364→      } else {
365→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
366→        queryClient.invalidateQueries({
367→          queryKey: queryKeys.sessions.messages(variables.sessionId),
368→        });
369→      }
370→      // Roll back optimistic workspace status from snapshot
371→      if (context?.previousWorkspaceByRepo?.length) {
372→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
373→          queryClient.setQueryData(key, data);
374→        });
375→      } else {
376→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
377→      }
378→    },
379→
380→    onSettled: async (_, error, variables) => {
381→      if (!error) {
382→        const hasImages = (() => {
383→          try {
384→            const parsed = JSON.parse(variables.content);
385→            return (
386→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
387→            );
388→          } catch {
389→            return false;
390→          }
391→        })();
392→        const session = queryClient.getQueryData<Session>(
393→          queryKeys.sessions.detail(variables.sessionId)
394→        );
395→        track("session_message_sent", {
396→          session_id: variables.sessionId,
397→          has_images: hasImages,
398→          model: variables.model,
399→          agent_type: session?.agent_type,
400→          message_count: session?.message_count,
401→          context_used_percent: session?.context_used_percent,
402→        });
403→      }
404→      // No incrementalFetchAndMerge needed — WS q:delta handles reconciliation.
405→      // The optimistic message stays visible until the delta arrives with the real message.
406→    },
407→  });
408→}
409→
410→/**
411→ * Stop session mutation
412→ */
413→export function useStopSession() {
414→  const queryClient = useQueryClient();
415→
416→  return useMutation({
417→    mutationFn: (sessionId: string) => SessionService.stop(sessionId),
418→    onSuccess: (_, sessionId) => {
419→      const session = queryClient.getQueryData<Session>(queryKeys.sessions.detail(sessionId));
420→      track("session_stopped", {
421→        session_id: sessionId,
422→        agent_type: session?.agent_type,
423→      });
424→      // Immediate invalidation for snappy UI feedback.
425→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
426→      queryClient.invalidateQueries({
427→        queryKey: queryKeys.sessions.detail(sessionId),
428→      });
429→      queryClient.invalidateQueries({
430→        queryKey: queryKeys.workspaces.all,
431→      });
432→    },
433→  });
434→}
435→
436→/**
437→ * Create a new session for a workspace.
438→ * Used when user opens a new chat tab (Cmd+T).
439→ * Backend creates the session and updates workspace.current_session_id.
440→ */
441→export function useCreateSession() {
442→  const queryClient = useQueryClient();
443→
444→  return useMutation({
445→    mutationFn: (workspaceId: string) => SessionService.createSession(workspaceId),
446→    onSuccess: (newSession, workspaceId) => {
447→      track("session_created", {
448→        workspace_id: workspaceId,
449→        agent_type: newSession?.agent_type,
450→        model: newSession?.model,
451→      });
452→      // Immediate invalidation for snappy UI feedback.
453→      // Backend also pushes via WS q:invalidate. React Query deduplicates.
454→      queryClient.invalidateQueries({
455→        queryKey: queryKeys.workspaces.all,
456→      });
457→      queryClient.invalidateQueries({
458→        queryKey: queryKeys.workspaces.detail(workspaceId),
459→      });
460→      queryClient.invalidateQueries({
461→        queryKey: queryKeys.sessions.byWorkspace(workspaceId),
462→      });
463→    },
464→  });
465→}
